func (q *Queries) ListPendingBuildsOrdered(ctx context.Context, limit int32) ([]TemplateBuild, error) {
	rows, err := q.db.Query(ctx, listPendingBuildsOrdered, limit)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []TemplateBuild{}
	for rows.Next() {
		var i TemplateBuild
		if err := rows.Scan(
			&i.ID,
			&i.TemplateID,
			&i.TeamID,
			&i.Status,
			&i.BuildSpecHash,
			&i.VmdHostID,
			&i.VmdBuildVmID,
			&i.ErrorMessage,
			&i.StartedAt,
			&i.FinalizedAt,
			&i.CreatedAt,
			&i.UpdatedAt,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

